// CleaningJobs sheet has 'status' (not cleaningStatus). Keep only PENDING, no cleaner assigned, no event yet, processingFlag empty (row-level lock).
const items = $input.all();
const filtered = items.filter(item => {
  const j = item.json || {};
  const status = (j.status ?? '').toString().trim();
  const cleanerId = (j.cleanerId ?? '').toString().trim();
  const hasEvent = (j.calendarEventId ?? '').toString().trim() !== '';
  const processingFlag = (j.processingFlag ?? '').toString().trim();
  return status === 'PENDING' && cleanerId === '' && !hasEvent && processingFlag === '';
});
return filtered;

// Attach Properties, CleanersProfile, and ALL CleaningJobs so Assign Cleaner can do availability checks inside the loop.
let properties = [];
let cleaners = [];
let allJobs = [];
try {
  const pNode = $('Read Properties');
  if (pNode && typeof pNode.all === 'function') properties = pNode.all();
} catch (_) {}
try {
  const cNode = $('Read CleanersProfile');
  if (cNode && typeof cNode.all === 'function') cleaners = cNode.all();
} catch (_) {}
try {
  const jNode = $('Read All Cleaning Jobs');
  if (jNode && typeof jNode.all === 'function') allJobs = jNode.all();
} catch (_) {}
const items = $input.all();
return items.map(item => ({ json: {
  ...item.json,
  _properties: Array.isArray(properties) ? properties : [],
  _cleanersProfile: Array.isArray(cleaners) ? cleaners : [],
  _allCleaningJobs: Array.isArray(allJobs) ? allJobs : []
} }));

// If Lookup returned 0 rows or empty row, use job only with fallbacks. Otherwise use first lookup row.
// propertyName: use reservation lookup first; else get from Properties sheet row matching propertyUid; else fallback to propertyUid.
const job = $('Split In Batches').last().json;
const items = $input.all();
const hasReservation = items.length > 0 && items[0].json?.bookingUid;
const lookup = hasReservation ? items[0].json : {};
let propertyName = (lookup.propertyName ?? '').toString().trim();
if (!propertyName && Array.isArray(job._properties)) {
  const pu = (job.propertyUid ?? '').toString().trim();
  const propRow = job._properties.find(r => {
    const j = r?.json ?? r;
    return (j?.propertyUid ?? '').toString().trim() === pu;
  });
  if (propRow) {
    const j = propRow?.json ?? propRow;
    propertyName = (j?.propertyName ?? '').toString().trim();
  }
}
if (!propertyName) propertyName = (job.propertyUid ?? '').toString().trim();
const merged = { ...job, ...lookup, propertyName, address: lookup.address ?? job.address ?? 'Address TBD' };
return [{ json: merged }];

// Merge cleaning job (from Split In Batches) with reservation (from Ensure One Item).
const job = $('Split In Batches').last().json;
const lookup = $input.first().json;
const merged = { ...job, ...lookup };
return [{ json: merged }];

// ASSIGN CLEANER Ã¢â‚¬â€� fixed property OR availability-based with round-robin tiebreak
const DURATION_HOURS = 3;
const item = $input.first().json;
const propertyUid = (item.propertyUid ?? '').toString().trim();

const properties   = Array.isArray(item._properties)      ? item._properties      : [];
const cleaners     = Array.isArray(item._cleanersProfile)  ? item._cleanersProfile : [];
const allJobs      = Array.isArray(item._allCleaningJobs)  ? item._allCleaningJobs : [];

if (properties.length === 0) throw new Error('No Properties data. Ensure Read Properties ran.');
if (cleaners.length === 0)   throw new Error('No CleanersProfile data. Ensure Read CleanersProfile ran.');

const get = (row, ...keys) => {
  const j = row && (row.json !== undefined ? row.json : row);
  if (!j || typeof j !== 'object') return '';
  for (const k of keys) {
    const v = j[k];
    if (v !== undefined && v !== null && String(v).trim() !== '') return String(v).trim();
  }
  return '';
};

// Ã¢â€�â‚¬Ã¢â€�â‚¬ Step 1: find property row Ã¢â€�â‚¬Ã¢â€�â‚¬
const propRow = properties.find(r => get(r, 'propertyUid') === propertyUid);
if (!propRow) throw new Error(`No Properties row for propertyUid: ${propertyUid}.`);

const propertyNameFromSheet = get(propRow, 'propertyName');
const fixedCleanerId        = get(propRow, 'fixedCleanerId');

// Ã¢â€�â‚¬Ã¢â€�â‚¬ Step 2: resolve cleaner Ã¢â‚¬â€� fixed or availability Ã¢â€�â‚¬Ã¢â€�â‚¬
let assignedCleanerId;
let isFixed = false;

if (fixedCleanerId) {
  // Fixed assignment Ã¢â‚¬â€� bypass availability check
  assignedCleanerId = fixedCleanerId;
  isFixed = true;
} else {
  // Availability-based assignment
  const newStart = item.scheduledCleaningTimeUTC ? new Date(item.scheduledCleaningTimeUTC) : null;
  if (!newStart || isNaN(newStart.getTime())) throw new Error('Missing or invalid scheduledCleaningTimeUTC on job.');
  const newEnd = new Date(newStart.getTime() + DURATION_HOURS * 3600 * 1000);

  // Collect busy cleaner IDs from ASSIGNED jobs that overlap with new job window
  const busyCleanerIds = new Set();
  for (const jobRow of allJobs) {
    const j = jobRow?.json ?? jobRow;
    const jStatus    = (j?.status ?? '').toString().trim();
    const jCleanerId = (j?.cleanerId ?? '').toString().trim();
    const jBookingUid = (j?.bookingUid ?? '').toString().trim();
    // Skip: not ASSIGNED, no cleaner, or this is the same job
    if (jStatus !== 'ASSIGNED') continue;
    if (!jCleanerId) continue;
    if (jBookingUid === (item.bookingUid ?? '').toString().trim()) continue;
    // Skip if missing scheduledCleaningTimeUTC Ã¢â‚¬â€� treat as non-blocking
    const startStr = (j?.scheduledCleaningTimeUTC ?? '').toString().trim();
    if (!startStr) continue;
    const existStart = new Date(startStr);
    if (isNaN(existStart.getTime())) continue;
    const existEnd = new Date(existStart.getTime() + DURATION_HOURS * 3600 * 1000);
    // Standard interval overlap: existStart < newEnd AND existEnd > newStart
    if (existStart < newEnd && existEnd > newStart) {
      busyCleanerIds.add(jCleanerId);
    }
  }

  // Available cleaners = all cleaners minus busy ones
  const availableCleaners = cleaners.filter(r => {
    const cId = get(r, 'cleanerId');
    return cId && !busyCleanerIds.has(cId);
  });

  if (availableCleaners.length === 0) {
    // Signal no-cleaner-found Ã¢â‚¬â€� handled by downstream IF node
    return [{ json: { ...item, _noCleanerAvailable: true, propertyName: propertyNameFromSheet || item.propertyName || propertyUid } }];
  }

  if (availableCleaners.length === 1) {
    assignedCleanerId = get(availableCleaners[0], 'cleanerId');
  } else {
    // Multiple available Ã¢â‚¬â€� check reset then pick lowest assignmentCount
    const now = new Date();
    // Reset counts if any cleaner's resetDate has passed
    for (const r of availableCleaners) {
      const j = r?.json ?? r;
      const resetDateStr = (j?.assignmentCountResetDateUTC ?? '').toString().trim();
      if (resetDateStr) {
        const resetDate = new Date(resetDateStr);
        if (!isNaN(resetDate.getTime()) && now >= resetDate) {
          // Mark for reset Ã¢â‚¬â€� actual sheet update done in Increment node
          if (j) j._needsReset = true;
        }
      }
    }
    // Pick cleaner with lowest count (treat missing/reset as 0)
    let best = null;
    let bestCount = Infinity;
    for (const r of availableCleaners) {
      const j = r?.json ?? r;
      const needsReset = j?._needsReset === true;
      const count = needsReset ? 0 : parseInt(j?.assignmentCount ?? '0', 10) || 0;
      const cId = get(r, 'cleanerId');
      if (count < bestCount || (count === bestCount && cId < (best?.id ?? 'Ã¯Â¿Â¿'))) {
        bestCount = count;
        best = { id: cId, needsReset };
      }
    }
    assignedCleanerId = best.id;
  }
}

// Ã¢â€�â‚¬Ã¢â€�â‚¬ Step 3: get cleaner details Ã¢â€�â‚¬Ã¢â€�â‚¬
const cleanerRow = cleaners.find(r => get(r, 'cleanerId') === assignedCleanerId);
if (!cleanerRow) throw new Error(`No CleanersProfile row for cleanerId: ${assignedCleanerId}.`);

const email      = get(cleanerRow, 'email');
const calendarId = get(cleanerRow, 'calendarId', 'calendar ID');
const name       = get(cleanerRow, 'name');
const phone      = get(cleanerRow, 'phone');

const assignedAt = new Date().toISOString();
const out = {
  ...item,
  cleanerId:         assignedCleanerId,
  cleanerEmail:      email      || item.cleanerEmail      || '',
  cleanerCalendarId: calendarId || item.cleanerCalendarId || '',
  cleanerName:       name       || item.cleanerName       || '',
  assignedCleaner:   name       || item.assignedCleaner   || '',
  cleanerContact:    phone      || item.cleanerContact    || '',
  assignedAt,
  status: 'ASSIGNED',
  propertyName: propertyNameFromSheet || item.propertyName || propertyUid,
  _isFixedAssignment: isFixed,
  _noCleanerAvailable: false
};
delete out._properties;
delete out._cleanersProfile;
delete out._allCleaningJobs;
return [{ json: out }];

const BASE_URL = 'https://n8n-forms.vercel.app';
const bookingUid = $json.bookingUid;
const cleanerId = $json.cleanerId;
const params = 'bookingId=' + encodeURIComponent(bookingUid || '') + '&cleanerId=' + encodeURIComponent(cleanerId || '');
const clockInLink = BASE_URL + '/clockin?' + params;
const checkoutLink = BASE_URL + '/checkout?' + params;
return [{ json: { ...$input.first().json, clockInLink, checkoutLink } }];

// Strict UTC only. Use scheduledCleaningTimeUTC from the original job (Split In Batches), not from trimmed update output.
// No 11:00 logic, no cleaningDate/checkOut fallbacks.
const DURATION_HOURS = 3;
// Always pull the full job (with scheduledCleaningTimeUTC) from Split In Batches.
const job = (() => {
  try {
    const n = $('Split In Batches');
    if (n && typeof n.last === 'function') {
      const v = n.last().json;
      if (v && typeof v === 'object') return v;
    }
  } catch (_) {}
  const current = $input.first()?.json;
  return current && typeof current === 'object' ? current : {};
})();
const startTime = job.scheduledCleaningTimeUTC;
if (!startTime || typeof startTime !== 'string' || startTime.trim() === '')
  throw new Error('Missing scheduledCleaningTimeUTC');
const startDate = new Date(startTime.trim());
if (isNaN(startDate.getTime()))
  throw new Error('Invalid scheduledCleaningTimeUTC');
const endDate = new Date(startDate.getTime() + DURATION_HOURS * 3600 * 1000);
const endTime = endDate.toISOString();
// Merge timing fields back onto the latest item in the chain so downstream nodes see them.
const base = $input.first()?.json || job;
return [{ json: { ...base, startTime: startTime.trim(), endTime, durationHours: DURATION_HOURS } }];

