// Increment assignmentCount for the assigned cleaner.
// Look up current count from CleanersProfile and compute reset date.
const item = $input.first().json;
const cleanerId = (item.cleanerId ?? '').toString().trim();
const now = new Date();
const nextReset = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth() + 1, 1));
const nextResetISO = nextReset.toISOString();

// Look up current assignmentCount from CleanersProfile
const allCleaners = $("Read CleanersProfile").all().map(i => i.json);
const profile = allCleaners.find(c => (c.cleanerId ?? '').toString().trim() === cleanerId);

// Safe count computation â€” handles empty string, undefined, null, NaN
const rawCount = profile?.assignmentCount;
const parsedCount = (rawCount !== undefined && rawCount !== null && String(rawCount).trim() !== '') ? parseInt(String(rawCount).trim(), 10) : 0;
const safeCount = isNaN(parsedCount) ? 0 : parsedCount;

if (item._isFixedAssignment || !cleanerId) {
  return [{ json: {
    ...item,
    _incrementCleanerId: cleanerId,
    _nextResetISO: nextResetISO,
    _currentCount: String(safeCount),
    _needsReset: false
  } }];
}
return [{ json: {
  ...item,
  _incrementCleanerId: cleanerId,
  _nextResetISO: nextResetISO,
  _currentCount: String(safeCount),
  _needsReset: item._needsReset === true
} }];
